import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  CreditCard, Plus, Calendar, Trash2, 
  ArrowRight, PieChart, Wallet, AlertCircle 
} from 'lucide-react';

const Cartoes = () => {
  const [cartoes, setCartoes] = useState([]);
  const [loading, setLoading] = useState(true);

  // Cores seguindo o padrão vibrante do Dashboard
  const colors = {
    primary: '#4361ee',
    secondary: '#7209b7',
    accent: '#f72585',
    success: '#4caf50',
    warning: '#ff9800'
  };

  useEffect(() => {
    fetchCartoes();
  }, []);

  async function fetchCartoes() {
    setLoading(true);
    const { data, error } = await supabase
      .from('cartoes')
      .select('*')
      .order('nome', { ascending: true });

    if (!error) setCartoes(data || []);
    setLoading(false);
  }

  const formatMoney = (v) => 
    `R$ ${parseFloat(v).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  return (
    <div className="fade-in" style={{ padding: '20px', backgroundColor: '#f0f2f5', minHeight: '100vh' }}>
      
      {/* HEADER DA PÁGINA */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <div>
          <h2 style={{ display: 'flex', alignItems: 'center', gap: '10px', color: '#333', margin: 0 }}>
            <CreditCard size={28} color={colors.primary} /> Gerenciamento de Cartões
          </h2>
          <p style={{ color: '#636e72', margin: '5px 0 0 0' }}>Gerencie seus limites e datas de fechamento</p>
        </div>
        
        <button style={btnNovoStyle(colors.primary)}>
          <Plus size={20} /> Novo Cartão
        </button>
      </div>

      {/* GRID DE CARTÕES */}
      <div style={gridStyle}>
        {cartoes.map((cartao) => (
          <div key={cartao.id} style={cartaoEstilizado(cartao.cor || colors.primary)}>
            <div style={cardGlassEffect}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <div>
                  <div style={{ opacity: 0.8, fontSize: '0.75rem', fontWeight: 600, textTransform: 'uppercase' }}>Banco / Apelido</div>
                  <div style={{ fontSize: '1.4rem', fontWeight: 800, marginBottom: '20px' }}>{cartao.nome}</div>
                </div>
                <div style={chipStyle} />
              </div>

              <div style={{ marginBottom: '20px' }}>
                <div style={{ opacity: 0.8, fontSize: '0.75rem', fontWeight: 600 }}>LIMITE TOTAL</div>
                <div style={{ fontSize: '1.6rem', fontWeight: 700 }}>{formatMoney(cartao.limite)}</div>
              </div>

              <div style={{ display: 'flex', gap: '20px' }}>
                <div>
                  <div style={{ opacity: 0.8, fontSize: '0.65rem', fontWeight: 600 }}>FECHAMENTO</div>
                  <div style={{ fontWeight: 700 }}>Dia {cartao.dia_fechamento}</div>
                </div>
                <div>
                  <div style={{ opacity: 0.8, fontSize: '0.65rem', fontWeight: 600 }}>VENCIMENTO</div>
                  <div style={{ fontWeight: 700 }}>Dia {cartao.dia_vencimento}</div>
                </div>
              </div>
            </div>
            
            <div style={cartaoFooterStyle}>
              <button style={actionBtnStyle} title="Ver Gastos">
                <PieChart size={18} />
              </button>
              <button style={{...actionBtnStyle, color: '#ff4d4d'}} title="Excluir">
                <Trash2 size={18} />
              </button>
            </div>
          </div>
        ))}

        {/* CARD DE ADICIONAR (Vazio/Dashed) */}
        <div style={cardAddPlaceholder}>
           <div style={{ textAlign: 'center', color: '#b2bec3' }}>
              <Plus size={40} style={{ marginBottom: '10px' }} />
              <div style={{ fontWeight: 600 }}>Adicionar Cartão</div>
           </div>
        </div>
      </div>

      {/* RESUMO RÁPIDO ABAIXO DOS CARDS */}
      <div style={{ marginTop: '40px' }}>
        <h3 style={{ color: '#333', marginBottom: '20px' }}>Resumo de Crédito</h3>
        <div style={gridStyle}>
            <SummaryCard 
                title="Crédito Total Disponível" 
                value={formatMoney(cartoes.reduce((acc, c) => acc + c.limite, 0))}
                icon={<Wallet color={colors.success} />}
            />
            <SummaryCard 
                title="Cartões Ativos" 
                value={cartoes.length}
                icon={<CreditCard color={colors.primary} />}
            />
        </div>
      </div>
    </div>
  );
};

/* COMPONENTES INTERNOS */
const SummaryCard = ({ title, value, icon }) => (
  <div style={{ backgroundColor: 'white', padding: '20px', borderRadius: '16px', display: 'flex', alignItems: 'center', gap: '15px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)' }}>
    <div style={{ backgroundColor: '#f8f9fa', padding: '12px', borderRadius: '12px' }}>{icon}</div>
    <div>
        <div style={{ fontSize: '0.8rem', color: '#636e72', fontWeight: 600, textTransform: 'uppercase' }}>{title}</div>
        <div style={{ fontSize: '1.4rem', fontWeight: 800, color: '#2d3436' }}>{value}</div>
    </div>
  </div>
);

/* ESTILOS EM OBJETOS */
const gridStyle = {
  display: 'grid',
  gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))',
  gap: '25px'
};

const cartaoEstilizado = (cor) => ({
  background: `linear-gradient(135deg, ${cor}, #2d3436)`,
  borderRadius: '20px',
  color: 'white',
  minHeight: '220px',
  position: 'relative',
  display: 'flex',
  flexDirection: 'column',
  boxShadow: '0 10px 20px rgba(0,0,0,0.15)',
  transition: 'transform 0.3s ease',
  cursor: 'pointer'
});

const cardGlassEffect = {
  padding: '25px',
  flexGrow: 1,
  background: 'rgba(255, 255, 255, 0.05)',
  backdropFilter: 'blur(5px)',
  borderRadius: '20px 20px 0 0',
  border: '1px solid rgba(255, 255, 255, 0.1)'
};

const cartaoFooterStyle = {
  backgroundColor: 'rgba(0,0,0,0.2)',
  padding: '10px 20px',
  borderRadius: '0 0 20px 20px',
  display: 'flex',
  justifyContent: 'flex-end',
  gap: '15px'
};

const chipStyle = {
  width: '45px',
  height: '35px',
  background: 'linear-gradient(135deg, #ffd700, #daa520)',
  borderRadius: '8px',
  position: 'relative',
  boxShadow: 'inset 0 0 5px rgba(0,0,0,0.2)'
};

const actionBtnStyle = {
  background: 'none',
  border: 'none',
  color: 'white',
  cursor: 'pointer',
  padding: '5px',
  opacity: 0.8,
  transition: 'opacity 0.2s'
};

const btnNovoStyle = (color) => ({
  backgroundColor: color,
  color: 'white',
  border: 'none',
  padding: '10px 20px',
  borderRadius: '12px',
  fontWeight: 600,
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  cursor: 'pointer',
  boxShadow: `0 4px 14px ${color}50`
});

const cardAddPlaceholder = {
    border: '3px dashed #d1d8e0',
    borderRadius: '20px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    minHeight: '220px',
    cursor: 'pointer',
    transition: 'all 0.3s ease'
};

export default Cartoes;
